"""
MKT Christ — Luke all 24 chapters
Output: data/commentary/mkt-christ/luke.json
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "1": {
    "46": '<p>A type: the Magnificat. Mary\'s song is shaped by Hannah\'s prayer (1 Sam 2:1-10) — Hannah as the type of the Spirit-filled woman through whom the Lord\'s anointed enters the world. But the Magnificat exceeds Hannah\'s song: where Hannah praised for her personal vindication, Mary praises for the eschatological reversal that the incarnation initiates for all the humble and hungry of Israel and the world. The type (Hannah/Samuel) points to the antitype (Mary/Jesus) not as mere parallel but as fulfillment: what Hannah\'s prayer anticipated (the exaltation of the humble, the strength of the LORD\'s anointed) is now the content of the incarnation itself.</p>',
    "68": '<p>A fulfillment: blessed be the Lord God of Israel, for he has visited and redeemed his people. Zechariah\'s Benedictus identifies the births of John and Jesus as the visitation (episkope) of YHWH that all the prophets promised. The OT motif of divine visitation (YHWH visiting his people in mercy or judgment) reaches its fulfillment in the incarnation: God personally visits his people not through a prophet or angel but in the person of his Son. The redemption (lytrosis, v.68; lytrosan, v.74) is the Exodus-liberation pattern now applied to redemption from enemies (political) and from sin (spiritual), with both dimensions present.</p>'
  },
  "2": {
    "11": '<p>A direct revelation: a Savior, who is Christ the Lord, has been born for you in the city of David. The angelic announcement at the shepherds concentrates Luke\'s Christology in a single sentence. The Savior born in David\'s city is the fulfillment of the Davidic covenant, the messianic hope, and the divine rescue promised throughout the OT. Luke\'s characteristic soter (Savior) title connects Jesus to the salvation history of Israel (YHWH as Israel\'s only savior, Isa 43:11) while the details of the manger, the shepherds, and the town of Bethlehem anchor the salvation in the most ordinary and humble circumstances — the divine Savior in a feeding trough.</p>',
    "32": '<p>A fulfillment: a light for revelation to the Gentiles and for glory to your people Israel. Simeon\'s Nunc Dimittis applies the Isaianic Servant vocation (Isa 49:6) to the infant Jesus: he is the Servant who is a light to the nations. Luke\'s Gospel will be the narrative of this dual fulfillment — the glory of Israel (through the Jewish mission) and the light to the Gentiles (through the Gentile mission that Acts continues). The infant who cannot yet speak is already identified as the one in whom the universal Servant mission will be embodied and accomplished.</p>'
  },
  "4": {
    "18": '<p>A direct revelation: the Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor. The Nazareth synagogue scene is Luke\'s programmatic statement of the Christological mission. Jesus reads Isa 61:1-2 and declares today this scripture has been fulfilled in your hearing (v.21) — the most explicit self-identification with the Isaianic Servant in the Synoptic Gospels. Luke presents the Christ\'s mission as the Jubilee: release to captives (from sin and from evil powers), sight to the blind, freedom for the oppressed, the year of the Lord\'s favor. The entire Gospel is the unfolding of this Jubilee-mission.</p>',
    "43": '<p>A direct revelation: I must preach the good news of the kingdom of God to the other towns as well; for I was sent for this purpose. The dei (it is necessary) of v.43 is one of Luke\'s most important theological terms — divine necessity shapes the mission at every point. Jesus was sent (apestalen) — the mission is not self-chosen but given by the Father. The kingdom of God that Jesus preaches is the reign of God becoming present in his own person; to hear Jesus is to encounter the kingdom\'s arrival.</p>'
  },
  "7": {
    "22": '<p>A fulfillment: go and tell John what you have seen and heard — the blind receive their sight, the lame walk, lepers are cleansed, the deaf hear, the dead are raised, the poor have good news proclaimed. Jesus\'s answer to the imprisoned John is the definitive self-identification from Isaiah: the signs that he lists are precisely the signs that Isaiah promised when YHWH comes to save (Isa 35:5-6, 61:1). Christ\'s identity is proven not by Messianic title-claim but by Isaianic sign-fulfillment; the question is not what do you claim to be? but what do you see happening? The works are the revelation.</p>'
  },
  "9": {
    "51": '<p>A direct revelation: when the days drew near for him to be taken up, he set his face to go to Jerusalem. Luke\'s travel-narrative framing (9:51-19:44) presents the entire journey to Jerusalem as a deliberate movement toward the passion, resurrection, and ascension. Jesus does not drift toward Jerusalem; he sets his face (Isa 50:7, the Servant who sets his face like flint to face opposition). Every parable and teaching in the travel narrative is colored by this deliberate journey toward the cross. The Christological claim is implicit: the one who moves with this resolve toward his own death is the one who has freely accepted the Father\'s mission from eternity.</p>'
  },
  "15": {
    "20": '<p>A revelation of God: the father of the prodigal son runs, embraces, and restores without condition. The father in the parable is transparently the image of God — no other first-century Jewish father would run (an undignified act) to embrace a disgraced son before any apology had been given. The parable is Jesus\'s defense of his own practice (receiving sinners) by revealing the Father\'s character: God himself is the running father who hosts the party for the found son and pleads with the older brother. Every feature of the father\'s excess (running, robe, ring, sandals, feast, self-humiliation at the party\'s edge) is a portrait of divine grace preceding, enabling, and exceeding human repentance.</p>'
  },
  "19": {
    "10": '<p>A direct revelation: the Son of Man came to seek and to save the lost. Luke\'s mission-statement frames the Zacchaeus encounter as the paradigmatic instance of the Son of Man\'s seeking-saving mission. The three parables of Luke 15 and the Zacchaeus narrative are the lived theology of Luke 19:10: the lost sheep sought by the shepherd, the lost coin sought by the woman, the lost son welcomed by the father, and now the lost Zacchaeus sought-and-found by the Son of Man himself. The mission of Luke\'s Gospel is the living-out of this one sentence, fulfilled supremely in the cross (where the Son of Man gives himself to save the utterly lost).</p>'
  },
  "22": {
    "20": '<p>A fulfillment: this cup that is poured out for you is the new covenant in my blood. Luke\'s cup-word (with the new covenant language from Jer 31:31-34) is the most explicit Jeremianic citation in the passion narratives. The new covenant — written on the heart, bringing forgiveness of sins, creating universal knowledge of YHWH — is inaugurated in the cup of Jesus\'s blood. The Passover context connects the new covenant blood to the Exodus blood (the lamb\'s blood that protected from the destroying angel): Christ\'s blood is simultaneously the final Passover (ending the old covenant\'s provisional atonement) and the new covenant\'s ratifying sacrifice.</p>',
    "37": '<p>A fulfillment: this scripture must be fulfilled in me: And he was numbered with the transgressors. Jesus\'s citation of Isa 53:12 before his arrest is the clearest evidence in the Synoptics that Jesus explicitly understood his death as the fulfillment of the Servant\'s vicarious suffering. The verb dei (must be fulfilled) indicates divine necessity: the Servant\'s path of bearing sin for the many was not merely predictive of his death but constitutive of the divine plan from which the cross received its saving power. The numbered-with-transgressors (arrested as a criminal) is the humiliation that precedes the Servant\'s exaltation.</p>'
  },
  "23": {
    "43": '<p>A direct revelation: today you will be with me in paradise. The word to the penitent criminal is the most compressed eschatological promise in the Gospels: today (the dying day, no purgatorial delay), with me (personal presence with Christ, not merely a blessed state), in paradise (the garden-restored, the original Eden-with-God now restored). The dying Christ who is in the process of bearing sin for the many simultaneously promises the thief immediate eschatological fellowship. The promise grounds the community\'s confidence: if even the dying criminal is welcomed today, the resurrection-hope of all who trust Christ is secured.</p>',
    "46": '<p>A direct revelation: Father, into your hands I commit my spirit. Luke\'s Christ dies with Ps 31:5 as his final prayer — the trust-language of the righteous sufferer who commits himself to the faithful Father at death. The Father-address maintains the intimate relationship that defined the whole of Luke\'s Christological portrayal (Abba in Gethsemane, 22:42; this prayer at death). The Spirit commended to the Father\'s hands is the Spirit that will be poured out at Pentecost (Acts 2) — even in death the Son\'s Spirit remains in the Father\'s keeping, to be given back in the resurrection and then poured out on the community.</p>'
  },
  "24": {
    "27": '<p>A direct revelation: beginning with Moses and all the Prophets he interpreted to them in all the Scriptures the things concerning himself. The risen Christ\'s Emmaus hermeneutic is the epistemological key to Luke\'s entire Gospel: the OT is about Christ, and only the risen Christ can unlock its true meaning. The burning hearts (v.32) indicate that proper reading of Scripture is simultaneously encounter with the risen Christ — not merely information about him but the experience of his presence through the word. Luke\'s Gospel has been narrating what the risen Christ explained: the whole story of Israel (from Genesis through the Prophets) was the long preparation for and anticipation of what Jesus accomplished in Jerusalem.</p>',
    "46": '<p>A direct revelation: it is necessary that the Christ should suffer and on the third day rise from the dead, and that repentance for the forgiveness of sins should be proclaimed in his name to all nations. The risen Christ\'s final hermeneutical statement to the disciples declares the canonical shape of the Christological narrative: suffering → resurrection is the divinely necessary arc (dei), and the worldwide mission to proclaim forgiveness in his name is its equally necessary consequence. Luke 24:46-47 is the theological thesis of Acts, which will narrate exactly this proclamation going from Jerusalem to the ends of the earth. The Christ\'s mission is complete; the community\'s mission is just beginning.'
  }
}

# Gap-fill ch 17 — all 37 verses
FILL_CH17 = {
  "17": {
    "1": "<p>&#8220;Things that cause people to stumble are bound to come, but woe to anyone through whom they come&#8221; &#8212; the dual acknowledgment: scandalous stumbling-blocks (<em>skandala</em>) are inevitable in a fallen world, yet responsibility for causing them remains. Christ addresses the protection of &#8220;little ones&#8221; (the vulnerable and young in faith) as a primary ethical concern. The &#8220;woe&#8221; echoes the prophetic woes of Isa 5 and 10 (woe to those who oppress the weak). The Christological ground: Christ himself became a stumbling block (1 Cor 1:23: &#8220;Christ crucified, a stumbling block to Jews&#8221;), yet he never caused others to stumble &#8212; his concern is their protection.</p>",
    "2": "<p>&#8220;It would be better for them to be thrown into the sea with a millstone tied around their neck than to cause one of these little ones to stumble&#8221; &#8212; the hyperbolic comparison makes the gravity of causing another&#8217;s spiritual ruin absolute. The millstone-drowning recalls the judgment imagery of Jer 51:63&#8211;64 (the scroll cast into the Euphrates as a sign of Babylon&#8217;s destruction). The &#8220;little ones&#8221; are those the kingdom values most highly &#8212; the same community that the Father does not wish to see lost (Matt 18:14: &#8220;your Father in heaven is not willing that any of these little ones should perish&#8221;). Christ as protector of the vulnerable grounds the warning.</p>",
    "3": "<p>&#8220;If a brother or sister sins against you, rebuke them; and if they repent, forgive them&#8221; &#8212; the community ethics of forgiveness. The rebuke-and-forgiveness sequence mirrors the divine pattern: God rebukes sin (the prophets) and forgives the repentant (Ps 103:3; Isa 55:7). Christ who rebukes and forgives (7:47&#8211;48) is the model for the community&#8217;s interpersonal life. The requirement to rebuke (rather than simply suffer the wrong in silence) protects the brother&#8217;s soul as well as the relationship &#8212; the goal is restoration, not retribution.</p>",
    "4": "<p>&#8220;Even if they sin against you seven times in a day and seven times come back to you saying, I repent, you must forgive them&#8221; &#8212; the sevenfold forgiveness expands the Mosaic limit (Lev 19:18) and anticipates Jesus&#8217;s answer to Peter&#8217;s &#8220;how many times shall I forgive?&#8221; question (Matt 18:21&#8211;22: &#8220;not seven times, but seventy-seven times&#8221;). The limitless forgiveness Christ requires is the forgiveness he himself provides: &#8220;forgive us our debts as we forgive our debtors&#8221; (Matt 6:12). The cross is the ground of forgiveness that makes limitless human forgiveness possible &#8212; receiving the infinite forgiveness of God produces the ability to give limitless forgiveness to others.</p>",
    "5": "<p>&#8220;The apostles said to the Lord: Increase our faith!&#8221; &#8212; the apostles&#8217; request comes directly after the demanding call to limitless forgiveness &#8212; they recognize that such forgiveness exceeds natural capacity. The request is addressed to &#8220;the Lord&#8221; (<em>Kyriō</em>), signaling that faith is not self-generated but given by the one who is its source and perfecter (Heb 12:2: &#8220;Jesus, the pioneer and perfecter of faith&#8221;). The disciples&#8217; humility in asking for more faith reflects the correct posture: faith is Christ&#8217;s gift, not a human achievement to be mustered by will.</p>",
    "6": "<p>&#8220;If you have faith as small as a mustard seed, you can say to this mulberry tree, Be uprooted and planted in the sea, and it will obey you&#8221; &#8212; the mustard-seed faith answer inverts the expected logic: the disciples do not need more faith (a quantity problem) but genuine faith (a quality problem). The smallest real faith has extraordinary power because it is connected to the one in whom all power resides. The tree obeying faith&#8217;s command is the image of creation responding to the Creator&#8217;s authority mediated through those who trust him &#8212; the same authority by which Jesus commands storms (8:24) and demons (4:35).</p>",
    "7": "<p>The parable of the unworthy servants begins with a rhetorical question challenging the assumption of reward for duty: would a master thank a servant for coming in from the field and immediately invite him to dinner? The social reality (no, he would expect the servant to serve first) establishes the ground for the teaching. The point is not that God treats his servants as mere instruments, but that the disciples&#8217; posture before God should not be one of merit-calculation &#8212; the very kingdom they serve belongs to God, and their participation in it is already grace beyond any earned reward.</p>",
    "8": "<p>&#8220;Won&#8217;t he rather say: Prepare my supper, get yourself ready and wait on me while I eat and drink?&#8221; &#8212; the master&#8217;s expectation of service first reveals the servant&#8217;s proper role. Christologically, the parable is set within the frame of 12:37 (where the returning master serves his watchful servants) &#8212; the inversion: Jesus as the master who himself takes the servant&#8217;s posture (John 13:4&#8211;5) is not expected by the parable; it is the eschatological surprise that the other passage provides. Here the point is the disciples&#8217; own posture of humble service, not the master&#8217;s final generosity.</p>",
    "9": "<p>&#8220;Will he thank the servant because he did what he was told to do? I think not&#8221; &#8212; the parable pushes back against the logic of merited divine gratitude. The concept that God owes his servants reward for normal obedience is the frame being dismantled &#8212; the same frame that undergirds the Pharisees&#8217; covenant theology (obedience to Torah earns divine reward). The new covenant frame (grace alone, Eph 2:8&#8211;9) runs in a different direction: &#8220;for it is God who works in you to will and to act in order to fulfill his good purpose&#8221; (Phil 2:13) &#8212; even the obedience is a gift.</p>",
    "10": "<p>&#8220;So you also, when you have done everything you were told to do, should say: We are unworthy servants; we have only done our duty&#8221; &#8212; the conclusion of the parable is its Christological application: the proper posture before God is continual humility, not merit-accounting. The unworthy servant statement is not false modesty but accurate theology &#8212; before the holiness and grace of God, even obedient service is the least that can be offered. The disciples who have been given the kingdom (12:32) have received everything by grace; the posture of &#8220;unworthy servants&#8221; is the honest response to that gift.</p>",
    "11": "<p>&#8220;Jesus travelled along the border between Samaria and Galilee&#8221; &#8212; the geographic detail has Christological significance. The border-region is the marginal zone between Jewish and Samaritan territory &#8212; the space where the excluded and the marginalized existed. The ten lepers who meet Jesus at the village entrance are themselves in the marginal space required by law (Lev 13:46: &#8220;they must live alone; they must live outside the camp&#8221;). Christ operating in the liminal zone is the pattern of the incarnation: he meets the excluded at the boundary of exclusion.</p>",
    "12": "<p>The ten lepers standing at a distance (<em>porrōthen</em>) reflects both the legal requirement (Lev 13:45&#8211;46) and their own awareness of their unclean status. The ten-leper encounter is the largest single healing in Luke&#8217;s Gospel. The number ten has no symbolic significance beyond its narrative function &#8212; but the nine who do not return (v.17) represent the majority of those who receive healing without receiving the Healer. The distance the lepers maintain is the distance that Christ crosses: he responds to their cry before they have approached.</p>",
    "13": "<p>&#8220;Jesus, Master, have pity on us!&#8221; (<em>Epistata, eleēson hēmas</em>) &#8212; the cry of mercy from the margin. <em>Epistata</em> (Master, the one who stands over) is Luke&#8217;s distinctive title for Jesus (5:5; 8:24,45; 9:33,49) &#8212; used by disciples, not outsiders, which makes its use by lepers significant: they address him with a title that recognizes his authority. The plea for mercy (<em>eleos</em>, YHWH&#8217;s covenant love) is the fundamental petition that Christ answers throughout his ministry &#8212; the plea of the Psalms (Ps 6:2; 51:1; 123:3) now addressed directly to him.</p>",
    "14": "<p>&#8220;Go, show yourselves to the priests. And as they went, they were cleansed&#8221; &#8212; Jesus sends them to the priests without touching them or pronouncing them clean first &#8212; the healing happens obediently en route. The pattern echoes Naaman washing in the Jordan (2 Kgs 5:10&#8211;14): the healing comes through obedient action based on the prophet&#8217;s word alone, before any visible sign. Christ&#8217;s word is the effective cause; the obedience of faith is the path along which the healing flows. The Levitical process (Lev 14) prescribes priest-verification as the condition for re-entry &#8212; Christ sends them into that process.</p>",
    "15": "<p>&#8220;One of them, when he saw he was healed, came back, praising God in a loud voice&#8221; &#8212; the Samaritan who returns demonstrates that healing awakens the capacity for worship. The &#8220;loud voice&#8221; (<em>megalē phōnē</em>) of praise mirrors the angelic announcement of great joy (2:10) and the crowd&#8217;s praise at the triumphal entry (19:37) &#8212; the praise of those who recognize what God has done. The return to Jesus is the return to the source of the blessing &#8212; and the one who returns discovers that the healing is the entry-point to a deeper salvation (v.19: &#8220;your faith has saved you&#8221;).</p>",
    "16": "<p>&#8220;He threw himself at Jesus&#8217; feet and thanked him &#8212; and he was a Samaritan&#8221; &#8212; the prostration at Jesus&#8217; feet (the posture of worship) is the same posture the demoniac takes after healing (8:35) and the disciples after the storm-stilling (Matt 14:33: &#8220;they worshipped him saying, Truly you are the Son of God&#8221;). Luke&#8217;s parenthetical identification (&#8220;he was a Samaritan&#8221;) echoes the centurion pericope (7:9: &#8220;I have not found such great faith even in Israel&#8221;) &#8212; the outsider recognizes and honors Christ while those closer to the covenant do not return.</p>",
    "17": "<p>&#8220;Were not all ten cleansed? Where are the other nine?&#8221; &#8212; Jesus&#8217;s question expresses the sorrow of grace received without gratitude. The nine who do not return are not condemned explicitly &#8212; they may have fulfilled the Levitical requirement faithfully &#8212; but they miss the relational completion of their healing. The pattern mirrors Israel&#8217;s history: rescued from Egypt (Exod 14&#8211;15) and failing to give sustained gratitude and trust (Ps 106:7&#8211;13). Christ who gives healing to all ten shows grace without precondition; the question &#8220;where are the nine?&#8221; is the Father&#8217;s question in the Prodigal Son parable &#8212; the grief of love unreturned.</p>",
    "18": "<p>&#8220;Has no one returned to give praise to God except this foreigner?&#8221; &#8212; the Samaritan as &#8220;foreigner&#8221; (<em>allogenes</em>) is the one who recognizes what the insiders miss. The pattern continues: the Samaritan woman (John 4), the Centurion (7:9), and now this foreigner receive what the religious insiders bypass. The theme fulfills Isa 56:6&#8211;7 (&#8220;foreigners who bind themselves to the LORD&#8230; these I will bring to my holy mountain&#8221;) and Isa 49:6 (the Servant as &#8220;a light for the Gentiles&#8221;). The Samaritan&#8217;s gratitude is the foretaste of the Gentile mission&#8217;s grateful reception of the gospel.</p>",
    "19": "<p>&#8220;Rise and go; your faith has saved you (<em>ses&#333;ken</em>)&#8221; &#8212; the salvation-word given exclusively to the returning Samaritan. All ten were cleansed (<em>ekatharisthēsan</em>); only the one who returned is saved (<em>ses&#333;ken</em>). The distinction is Luke&#8217;s Christological point: physical healing (available to all who came with the ten) and soteriological salvation (available through personal faith and encounter with Jesus) are distinguishable. The foreigner who prostrates at Jesus&#8217;s feet receives the greater gift &#8212; the same pattern as the woman in Luke 7 (7:50: &#8220;your faith has saved you; go in peace&#8221;).</p>",
    "20": "<p>&#8220;The coming of the kingdom of God is not something that can be observed&#8221; &#8212; the Pharisees&#8217; question about the timing of the kingdom&#8217;s coming receives an answer that fundamentally reframes the question. The kingdom is not a future geopolitical event that can be traced on a timeline; it is the present reality of God&#8217;s reign in Jesus&#8217;s person. &#8220;Not with careful observation&#8221; (<em>meta paratērēseōs</em>) &#8212; the Pharisees&#8217; watchfulness for datable signs is the wrong mode of attention. Christ as the kingdom-in-person (<em>entos hymōn</em>, in your midst/among you) is the answer they cannot see because they are looking elsewhere.</p>",
    "21": "<p>&#8220;The kingdom of God is in your midst&#8221; (<em>entos hymōn</em>) &#8212; the most compressed statement of realized eschatology in Luke. The kingdom is not &#8220;here&#8221; or &#8220;there&#8221; in a locatable place; it is present in the person of Jesus among the people. The phrase <em>entos hymōn</em> can mean &#8220;within you&#8221; (interior) or &#8220;among you&#8221; (relational-locative); given the address to Pharisees, &#8220;among you&#8221; is the more likely meaning &#8212; Jesus himself stands in their midst as the kingdom. The Christological claim: the kingdom has come because the King has come. The Pharisees are looking for a kingdom while standing in front of it.</p>",
    "22": "<p>&#8220;The time is coming when you will long to see one of the days of the Son of Man, but you will not see it&#8221; &#8212; the shift from addressing the Pharisees (vv.20&#8211;21) to the disciples (vv.22&#8211;37) marks the change in the eschatological teaching. The longing for &#8220;one of the days of the Son of Man&#8221; is the longing for the parousia from within the interval of persecution and suffering. The disciples will be in the position of Amos&#8217;s generation longing for the Day of the LORD (Amos 5:18&#8211;20) &#8212; but with greater understanding of both what the Son of Man&#8217;s days mean and how to wait for them.</p>",
    "23": "<p>&#8220;People will tell you, There he is! or Here he is! Do not go running off after them&#8221; &#8212; the false messiah warning. The instruction not to follow reports of localized sightings of the Son of Man is a warning against the eschatological credulity that will characterize the final period (cf. Matt 24:23&#8211;24: &#8220;if anyone tells you, Here is the Messiah! or, There he is! do not believe it&#8221;). The disciples&#8217; protection against deception is knowledge of the Son of Man&#8217;s nature: his coming will not be a local event requiring investigation but a universal, unmissable revelation (v.24).</p>",
    "24": "<p>&#8220;For the Son of Man in his day will be like the lightning, which flashes and lights up the sky from one end to the other&#8221; &#8212; the parousia as lightning from one end of the sky to the other is the most universal and unmissable image possible. Lightning cannot be localized or approached selectively; it illuminates everything simultaneously. The Son of Man&#8217;s coming is the ultimate revelation &#8212; the full disclosure of the one who was hidden in his earthly ministry (the messianic secret) is now universal and undeniable. The eschatological light is the same light who was &#8220;a light for revelation to the Gentiles&#8221; (2:32) &#8212; now fully revealed.</p>",
    "25": "<p>&#8220;But first he must suffer many things and be rejected by this generation&#8221; &#8212; the <em>dei</em> (must) of divine necessity inserts the cross between the present moment and the parousia. The Son of Man who will come in lightning-glory must first suffer and be rejected. This is the Isaianic pattern: the Servant who is &#8220;despised and rejected&#8221; (Isa 53:3) is the same one who &#8220;will be raised and lifted up and highly exalted&#8221; (Isa 52:13). The suffering-before-glory sequence is the shape of the incarnate Son&#8217;s story &#8212; and Luke emphasizes it at every point (9:22; 13:33; 17:25; 18:31&#8211;33; 24:26,46).</p>",
    "26": "<p>&#8220;Just as it was in the days of Noah, so also will it be in the days of the Son of Man&#8221; &#8212; the Noah typology for the parousia. Noah&#8217;s generation is the type of eschatological obliviousness: normal life proceeding as if the flood were not coming (1 Pet 3:20&#8211;21 extends the typology: the flood-water is a type of baptism). The Son of Man&#8217;s days will catch the world equally off-guard. The Noah comparison is also a sign of Christ&#8217;s divine prerogative: as YHWH determined the timing of the flood, the Son of Man determines the timing of the judgment (Acts 17:31: &#8220;he has set a day when he will judge the world with justice by the man he has appointed&#8221;).</p>",
    "27": "<p>&#8220;People were eating, drinking, marrying and being given in marriage up to the day Noah entered the ark. Then the flood came and destroyed them all&#8221; &#8212; the normalcy of pre-flood life is not condemned as sinful activity (eating, drinking, and marrying are all legitimate) but as obliviousness to the coming judgment. The &#8220;up to the day&#8221; structure is the eschatological warning: the ordinary activities of life will continue right up to the moment of the Son of Man&#8217;s coming &#8212; and then the ordinary will end. The call to readiness (12:35&#8211;40) is the antidote: continue normal life but with eschatological awareness.</p>",
    "28": "<p>&#8220;It was the same in the days of Lot. People were eating and drinking, buying and selling, planting and building&#8221; &#8212; the Sodom typology adds a second OT precedent (two witnesses required by law, Deut 19:15) for the same eschatological pattern. Lot&#8217;s generation is also engaged in legitimate commercial and agricultural activity &#8212; not idolatry or gross immorality at this particular moment, but complete indifference to the divine judgment approaching. The expansion beyond Noah (adding commerce and construction) widens the picture of ordinary life&#8217;s insufficiency as an eschatological protection.</p>",
    "29": "<p>&#8220;But the day Lot left Sodom, fire and sulphur rained down from heaven and destroyed them all&#8221; &#8212; the Sodom judgment (Gen 19:24&#8211;25) is the type of the eschatological fire. Fire from heaven as divine judgment appears in Elijah (2 Kgs 1:10&#8211;12), Ezekiel (Ezek 38:22), and Revelation (Rev 14:10; 20:9). The Son of Man&#8217;s day will be marked by this same sudden, comprehensive divine judgment. The Lot-rescue (Lot taken out before the fire falls) is a type of the eschatological deliverance of the righteous &#8212; the one taken (vv.34&#8211;36) before the judgment falls.</p>",
    "30": "<p>&#8220;It will be just like this on the day the Son of Man is revealed (<em>apokalyptetai</em>)&#8221; &#8212; the parousia as apocalypse, unveiling. The Son of Man who was &#8220;hidden&#8221; in his earthly ministry (the messianic secret) will be fully disclosed (<em>apokalypsis</em>) at the parousia &#8212; the same word used in 1 Pet 1:7 (&#8220;when Jesus Christ is revealed&#8221;) and 1 Cor 1:7 (&#8220;eagerly waiting for our Lord Jesus Christ to be revealed&#8221;). The suddenness of the Noah/Lot judgment-events becomes the suddenness of the Son of Man&#8217;s revelation &#8212; the moment of full Christological disclosure.</p>",
    "31": "<p>&#8220;On that day no one who is on the housetop&#8230; should go down to get them. Likewise, no one in the field should go back for anything&#8221; &#8212; the urgency of the day of the Son of Man leaves no time for earthly retrieval. The command echoes the Exodus urgency (Exod 12:11: &#8220;eat it in haste; it is the LORD&#8217;s Passover&#8221;) and anticipates the urgency of the disciples&#8217; mission (10:4: &#8220;do not take a purse or bag or sandals; and do not greet anyone on the road&#8221;). The kingdom&#8217;s urgency relativizes all possessions: the day of revelation requires total orientation to the coming Lord, not attachment to what is left behind.</p>",
    "32": "<p>&#8220;Remember Lot&#8217;s wife!&#8221; &#8212; the briefest warning in Luke is one of the most potent. Lot&#8217;s wife looking back (Gen 19:26) is the image of attachment to what is being left behind &#8212; the turned head that becomes a pillar of salt. The backward look is not nostalgia but the expression of a divided loyalty: she cannot fully commit to the direction of escape. Christologically, the warning applies to the disciples&#8217; journey with Jesus toward Jerusalem &#8212; &#8220;anyone who puts his hand to the plough and looks back is not fit for service in the kingdom of God&#8221; (9:62). The forward orientation of discipleship is the posture of those who expect the Son of Man.</p>",
    "33": "<p>&#8220;Whoever tries to keep their life will lose it, and whoever loses their life will preserve it&#8221; &#8212; the paradox of life-through-death that appears at each turning point of the Gospel (9:24; 14:26&#8211;27). The theme is grounded in the death-and-resurrection of Christ: the one who &#8220;did not come to be served but to serve, and to give his life as a ransom for many&#8221; (Mark 10:45) is the one who models life-through-loss. John 12:24&#8211;25 makes the connection explicit: &#8220;unless a grain of wheat falls to the ground and dies, it remains only a single seed. But if it dies, it produces many seeds.&#8221;</p>",
    "34": "<p>&#8220;I tell you, on that night two people will be in one bed; one will be taken and the other left&#8221; &#8212; the eschatological division running through the most intimate of human situations. The night setting implies the suddenness of the coming &#8212; even sleep provides no escape from the eschatological division. The &#8220;taken/left&#8221; language has been interpreted in various ways (taken to judgment or taken to safety), but the point is the absolute individuality of eschatological response: proximity does not confer solidarity. The division of the kingdom from the world reaches into the bedroom and the field.</p>",
    "35": "<p>&#8220;Two women will be grinding grain together; one will be taken and the other left&#8221; &#8212; the eschatological division reaches into shared labor. The grinding of grain was a communal task &#8212; women working together at the mill. Even shared work, shared life, and shared meals (v.26&#8211;28) do not create shared eschatological destiny. The criterion is not social solidarity but personal response to the Son of Man &#8212; the same principle that divides families (12:52&#8211;53: father against son, mother against daughter). Christ as the eschatological divider reveals the ultimate individuality of accountability before God.</p>",
    "36": "<p>&#8220;Two men will be in the field; one will be taken and the other left&#8221; &#8212; the third setting (bedroom, mill, field) completes the picture of the eschatological division reaching across all settings and activities of human life. The agricultural field recalls both the parable of the tares (Matt 13:24&#8211;30, 36&#8211;43) and the harvest imagery of the final judgment (Rev 14:14&#8211;20). The threefold repetition of the taken/left pattern (vv.34&#8211;36) serves to impress the universality of the eschatological distinction: no social context exempts anyone from the Son of Man&#8217;s coming assessment.</p>",
    "37": "<p>&#8220;Where, Lord? He replied: Where there is a dead body, there the eagles will gather&#8221; &#8212; the response to the disciples&#8217; &#8220;where?&#8221; question is a proverb from Job 39:30 (eagles gather to slaughter). The eschatological judgment will be self-evident &#8212; as the eagles unmistakably locate the carcass, so the Son of Man&#8217;s coming will be unmistakable. The answer deflects the &#8220;where&#8221; question (which is the wrong mode of eschatological attention, as v.21 established) with an image of inescapable revelation. The disciples should not look for a location but maintain readiness &#8212; when the day comes, its location will be self-evident.</p>"
  }
}

# Gap-fill ch 18 — all 43 verses
FILL_CH18 = {
  "18": {
    "1": "<p>&#8220;Then Jesus told his disciples a parable to show them that they should always pray and not give up (<em>enkakein</em>, lose heart)&#8221; &#8212; Luke&#8217;s characteristic paraenetic framing states the parable&#8217;s purpose before telling it. The persistent prayer-instruction is grounded in the eschatological context of ch 17: the disciples who are waiting for the Son of Man&#8217;s coming need a theology of prayer that sustains hope across the interval of waiting. The command &#8220;always pray and not give up&#8221; anticipates Paul&#8217;s &#8220;pray continually&#8221; (1 Thess 5:17) and the promised Spirit-intercession (Rom 8:26&#8211;27) that sustains prayer when it feels futile.</p>",
    "2": "<p>&#8220;In a certain city there was a judge who neither feared God nor cared what people thought&#8221; &#8212; the unjust judge&#8217;s double impiety (no fear of God, no shame before people) is the exact inversion of the biblical ideal: &#8220;fear God and keep his commandments&#8221; (Eccl 12:13); &#8220;do justice, love mercy, and walk humbly with your God&#8221; (Mic 6:8). The parable works by contrast (not comparison) with God: if even this godless judge eventually grants justice, how much more will the God who is utterly faithful to his own character bring justice to his chosen ones?</p>",
    "3": "<p>&#8220;And there was a widow in that city who kept coming to him with the plea: Grant me justice against my opponent&#8221; &#8212; the widow as the paradigmatic vulnerable person in the OT justice system (Exod 22:22&#8211;23: &#8220;do not take advantage of a widow or an orphan. If you do and they cry out to me, I will certainly hear their cry&#8221;; Isa 1:17: &#8220;defend the cause of the fatherless, plead the case of the widow&#8221;). The widow&#8217;s persistence is the model for the disciples&#8217; prayer &#8212; her cry for justice mirrors the church&#8217;s cry (&#8220;Maranatha&#8221; = &#8220;Come, Lord&#8221;; Rev 22:20) for the eschatological justice of the Son of Man&#8217;s coming.</p>",
    "4": "<p>&#8220;For some time he refused. But finally he said to himself: Even though I don&#8217;t fear God or care about people&#8230;&#8221; &#8212; the judge&#8217;s self-disclosure reveals the absence of any proper motivation for justice: no fear of God, no concern for reputation. His eventual compliance is purely self-interested &#8212; he wants to be left alone. The contrast with God heightens the parable&#8217;s logic: God has every motivation for justice (his own character, his covenant love for his people, his commitment to his own name), whereas the judge has none &#8212; and yet even the unjust judge grants the petition.</p>",
    "5": "<p>&#8220;Yet because this widow keeps bothering me, I will see that she gets justice, so that she won&#8217;t eventually come and attack me!&#8221; &#8212; the judge&#8217;s comic self-interest in avoiding harassment is the entirely unworthy motivation that still produces justice. The humor of the parable is the absurdity of comparing God&#8217;s response to this: God is nothing like the judge. The persistence that wore down the judge is the pattern of prayer Christ commends &#8212; not because God needs wearing down, but because persistence in prayer is the expression of faith that does not despair of his faithfulness (Heb 10:23: &#8220;let us hold unswerving to the hope we profess, for he who promised is faithful&#8221;).</p>",
    "6": "<p>&#8220;And the Lord said: Listen to what the unjust judge says&#8221; &#8212; the instruction to attend carefully to the unjust judge&#8217;s words is the rhetorical device of the <em>kal wa-homer</em> (lesser to greater) argument. If the corrupt judge&#8217;s words reveal that persistent petition wins justice from the most uncooperative source, the conclusion about God&#8217;s justice is irresistible. Luke&#8217;s narrative address (&#8220;the Lord said&#8221;) is one of the rare cases where the narrator uses the title &#8220;Lord&#8221; (<em>ho Kyrios</em>) for Jesus in narrative &#8212; signaling the divine authority of what follows.</p>",
    "7": "<p>&#8220;And will not God bring about justice for his chosen ones, who cry out to him day and night? Will he keep putting them off?&#8221; &#8212; the rhetorical question that applies the parable. The &#8220;chosen ones&#8221; (<em>eklektos</em>, the elect) cry out day and night &#8212; the perpetual cry of the suffering church for vindication and justice. The patience of God (&#8220;will he keep putting them off?&#8221; &#8212; expected answer: no) is the context for the promise of swift justice (v.8). Christologically, the cry of the elect is answered definitively at the cross (where the Judge bears the penalty that justice required) and consummated at the parousia.</p>",
    "8": "<p>&#8220;I tell you, he will see that they get justice, and quickly. However, when the Son of Man comes, will he find faith on the earth?&#8221; &#8212; the promise of swift justice is paired with the most searching eschatological question of the travel narrative. The Son of Man&#8217;s coming will bring the justice the elect have prayed for &#8212; but the question is whether the praying community will still exist: &#8220;will he find faith?&#8221; The juxtaposition of guaranteed justice and uncertain faith is the call to perseverance. The Son of Man comes as both vindicator and judge &#8212; and the parable of the widow is the call to maintain the persistent faith that his coming will reward.</p>",
    "9": "<p>&#8220;To some who were confident of their own righteousness and looked down on everyone else, Jesus told this parable&#8221; &#8212; the Pharisee/tax-collector parable is explicitly addressed to those with settled confidence in their own righteousness (<em>pepoithotas eph heautois hoti eisin dikaioi</em>). The target is not Pharisaic hypocrisy per se but the deeper problem of self-justification &#8212; the attempt to stand before God on the basis of one&#8217;s own moral achievement. The parable will demonstrate that justification comes from God alone, received in humility rather than claimed through performance.</p>",
    "10": "<p>Two men go up to the Temple to pray &#8212; both are practicing Jews engaged in legitimate religious activity. The Temple as the setting for the parable is significant: the place of atonement-sacrifice (the Yom Kippur rituals of Lev 16) is where both men approach God. The Pharisee&#8217;s prayer will reveal his assumption that he needs no atonement; the tax collector&#8217;s will reveal his knowledge that he does. The contrast is the contrast between those who approach the Cross as observers and those who approach it as desperate sinners.</p>",
    "11": "<p>&#8220;The Pharisee stood and prayed about himself: God, I thank you that I am not like other people &#8212; robbers, evildoers, adulterers &#8212; or even like this tax collector&#8221; &#8212; the Pharisee&#8217;s prayer is genuinely a prayer of thanksgiving &#8212; he is not lying about his observance. The problem is the comparison: his righteousness is defined in relation to other people rather than in relation to God&#8217;s holiness. The prayer &#8220;about himself&#8221; (<em>pros heauton</em>) is also possibly &#8220;to himself&#8221; &#8212; the prayer that addresses God in form but the self in content. It is a prayer that never looks up because it is busy looking around.</p>",
    "12": "<p>&#8220;I fast twice a week and give a tenth of all I get&#8221; &#8212; the Pharisee&#8217;s specific observances (fasting beyond Torah requirements; tithing even garden herbs, Matt 23:23) are scrupulous and genuine. He is not a hypocrite in the sense of pretending to things he does not do &#8212; he really does fast and tithe. The problem is the frame: these observances are the currency with which he believes he has purchased divine approval. The cross exposes the impossibility of this transaction: &#8220;a man is not justified by the works of the law&#8221; (Gal 2:16). No amount of fasting and tithing can purchase what only grace can give.</p>",
    "13": "<p>&#8220;But the tax collector stood at a distance. He would not even look up towards heaven, but beat his breast and said: God, have mercy on me, a sinner&#8221; &#8212; the posture and prayer of the tax collector are the model of authentic approach to God. The distance from the sanctuary, the downcast eyes, the breast-beating (the sign of grief and self-condemnation in Jewish mourning), and the single plea for mercy (<em>hilasthēti moi</em>, &#8220;be propitiated toward me&#8221; &#8212; the atonement vocabulary of Lev 16) reveal a person who knows he has no merit to offer. His prayer is the prayer that the entire sacrificial system was designed to enable.</p>",
    "14": "<p>&#8220;I tell you that this man, rather than the other, went home justified before God. For all those who exalt themselves will be humbled, and those who humble themselves will be exalted&#8221; &#8212; the verdict is Paul&#8217;s justification doctrine in narrative form. &#8220;Justified&#8221; (<em>dedikaiōmenos</em>) is the legal term for acquittal &#8212; declared righteous before the divine Judge. The tax collector who offers only the prayer of a sinner goes home with the verdict the Pharisee assumed he had already secured. Christologically, the tax collector&#8217;s justification is possible because the cross provides what his prayer could not &#8212; actual atonement (<em>hilasmos</em>, 1 John 2:2) before God.</p>",
    "15": "<p>&#8220;People were bringing babies to Jesus for him to place his hands on them&#8221; &#8212; the blessing of infants (<em>brephē</em>, newborns) follows immediately after the tax collector&#8217;s justification by humble faith. The connection is Christological: those who cannot do anything to merit entry into the kingdom (infants) are the paradigm of kingdom-citizenship (v.17). The disciples&#8217; rebuke of the parents reflects their misunderstanding of who belongs in the kingdom &#8212; the same misunderstanding that the parable of the two prayers exposes in a different register. Jesus corrects both: the self-justifying and the dismissal of the vulnerable.</p>",
    "16": "<p>&#8220;Let the little children come to me, and do not hinder them, for the kingdom of God belongs to such as these&#8221; &#8212; the kingdom belongs to the childlike. The children are not praised for innocence (the NT does not idealize childhood as sinless) but for their receptivity &#8212; they come to Jesus without pretense of merit and receive his touch. The &#8220;such as these&#8221; (<em>tōn toioutōn</em>) indicates that children are the model, not the only members: the kingdom belongs to those who approach as children. Christ&#8217;s embrace of infants is a type of the new creation&#8217;s welcome &#8212; &#8220;let the one who is thirsty come; let the one who wishes take the free gift of the water of life&#8221; (Rev 22:17).</p>",
    "17": "<p>&#8220;Truly I tell you, anyone who will not receive the kingdom of God like a little child will never enter it&#8221; &#8212; the condition for kingdom entry is the childlike posture of receptivity. The child who accepts a gift without earning it is the model for receiving the kingdom &#8212; which is itself a gift (12:32: &#8220;your Father has been pleased to give you the kingdom&#8221;). The impossibility of earning the kingdom by achievement (the Rich Ruler will demonstrate this in vv.18&#8211;27) is the counterpart to the possibility of receiving it as a gift. Christ as the giver of the kingdom demands only the openness of the child&#8217;s hands.</p>",
    "18": "<p>&#8220;A certain ruler asked him: Good teacher, what must I do to inherit eternal life?&#8221; &#8212; the Rich Ruler&#8217;s question contains its own theological problem: &#8220;what must I do&#8221; assumes that eternal life is achieved through action. The &#8220;inherit&#8221; (<em>klēronomeō</em>) language is inheritance language &#8212; and inheritance is typically received as a gift from a benefactor, not earned. The Christological irony: he asks the one who gives eternal life as a free gift how to earn it. His &#8220;doing&#8221; frame will be exposed by the radical demand of v.22 &#8212; which he cannot meet &#8212; and the resolution of v.27 (&#8220;what is impossible with man is possible with God&#8221;).</p>",
    "19": "<p>&#8220;Why do you call me good? No one is good &#8212; except God alone&#8221; &#8212; Jesus&#8217;s response is not a denial of his own goodness but a Christological probe: do you know what you&#8217;re saying when you call me good? If goodness belongs only to God, and you are calling me good, you are making a theological claim that requires examination. The question is the Socratic method applied to Christology: Jesus forces the ruler to think through the implications of his address. For those who confess that Jesus is Lord and God (John 20:28: &#8220;my Lord and my God!&#8221;), calling him &#8220;good&#8221; is entirely correct &#8212; Jesus is not denying this; he is testing whether the ruler knows what he is saying.</p>",
    "20": "<p>Jesus&#8217;s citation of the commandments (adultery, murder, theft, false testimony, honor parents) from the second table of the Decalogue (Exod 20:12&#8211;16) focuses on the relational commandments &#8212; duties to others. The omission of the first table (duties to God, including the prohibition of covetousness) is not accidental &#8212; the ruler&#8217;s violation will be revealed as covetousness: his attachment to his wealth is the &#8220;other gods&#8221; before the LORD (Exod 20:3&#8211;4). Christ as the one who fulfills the law (Matt 5:17) and embodies its summary (&#8220;love the Lord your God&#8230; love your neighbor&#8221;) is the one whose question probes the ruler&#8217;s obedience to both tables.</p>",
    "21": "<p>&#8220;All these I have kept since I was a boy&#8221; &#8212; the ruler&#8217;s self-assessment is sincere, not self-deceptive. Mark&#8217;s parallel notes that &#8220;Jesus looked at him and loved him&#8221; (Mark 10:21) &#8212; the response of genuine affection for someone near the kingdom. Yet the claim of complete second-table obedience since boyhood reveals the self-righteousness that the Pharisee&#8217;s prayer exposed: confident of one&#8217;s own righteousness before God. The first table&#8217;s requirement has not been examined &#8212; and v.22 will expose it through the single demand that unmasks the covetous attachment to wealth.</p>",
    "22": "<p>&#8220;You still lack one thing. Sell everything you have and give to the poor, and you will have treasure in heaven. Then come, follow me&#8221; &#8212; the radical demand reveals the first-table violation: his wealth is his god. The &#8220;one thing&#8221; lacking is the love of God with the whole heart &#8212; the single most important commandment that the ruler has not examined. The call to sell and follow is not a general command for all disciples (Luke records wealthy followers: Zacchaeus gives half, not all, 19:8) but the precise revelation of this ruler&#8217;s specific idolatry. Christ as the one who requires the whole heart (Deut 6:5) exposes the hidden idol.</p>",
    "23": "<p>&#8220;When he heard this, he became very sad, because he was very wealthy&#8221; &#8212; the sadness is the measure of the attachment: the ruler&#8217;s wealth holds him more tightly than the kingdom&#8217;s invitation. The word &#8220;very wealthy&#8221; (<em>plousios sphodra</em>) mirrors the &#8220;very sad&#8221; (<em>perilypos&#8221; egeneto sphodra</em>) &#8212; the extreme wealth produces extreme sadness. The ruler goes away, unlike the disciples who &#8220;left all and followed&#8221; (5:11,28). The theme of wealth as the competitor to kingdom-devotion runs from the Rich Fool (12:16&#8211;21) through Lazarus/Rich Man (16:19&#8211;31) &#8212; and this ruler stands at the crossroads between them.</p>",
    "24": "<p>&#8220;How hard it is for the rich to enter the kingdom of God!&#8221; &#8212; Jesus&#8217;s observation reverses the common theological assumption that wealth is a sign of divine blessing and therefore a path to the kingdom. The OT prosperity theology (Deut 28:1&#8211;14) is not denied but deepened: wealth can become the very obstacle to the kingdom that it might have prepared its possessor to serve. The Christological irony is complete in 2 Cor 8:9: the one who makes the kingdom available &#8220;became poor&#8221; &#8212; the rich Jesus of divine glory impoverished himself so that those impoverished by their wealth&#8217;s grip might receive the kingdom.</p>",
    "25": "<p>&#8220;Indeed, it is easier for a camel to go through the eye of a needle than for someone who is rich to enter the kingdom of God&#8221; &#8212; the hyperbolic impossibility (the largest animal in Levantine experience / the smallest aperture in daily use) states the case as absolute. The intended shock is the shock of complete impossibility: the disciples&#8217; stunned response (v.26: &#8220;who then can be saved?&#8221;) shows they heard it correctly. The hyperbole is not a medical impossibility about a small gate (&#8220;Needle&#8217;s Eye&#8221;) but a rhetorical shock-device &#8212; the point is that by human means, the rich man&#8217;s salvation is impossible.</p>",
    "26": "<p>&#8220;Those who heard this asked: Who then can be saved?&#8221; &#8212; the disciples&#8217; question is the right response to the camel/needle impossibility. If the wealthy &#8212; those who appear to have every advantage including God&#8217;s material blessing &#8212; cannot be saved by their own efforts, then no one can. The disciples move from particular case (this rich man) to universal question (who, then?) &#8212; and their question opens space for the decisive Christological answer of v.27. The question is the human recognition of the problem; Christ&#8217;s answer is the divine provision of the solution.</p>",
    "27": "<p>&#8220;What is impossible with man is possible with God&#8221; &#8212; the Christological resolution of the camel/needle impossibility. Human salvation (including the salvation of the rich from their idolatrous attachment to wealth) is not achievable by human effort &#8212; and God makes it possible. The statement echoes Gen 18:14 (&#8220;Is anything too hard for the LORD?&#8221;) and Jer 32:17,27 (&#8220;nothing is too hard for you&#8221;). The incarnation is the specific demonstration of what is impossible with men being accomplished by God: &#8220;God was reconciling the world to himself in Christ&#8221; (2 Cor 5:19). Zacchaeus (19:1&#8211;10) will be the living proof of this verse.</p>",
    "28": "<p>&#8220;Peter said to him: We have left all we had to follow you&#8221; &#8212; Peter&#8217;s statement invokes the disciples&#8217; actual practice of the demand that the rich ruler could not meet (5:11: &#8220;they pulled their boats up on shore, left everything and followed him&#8221;). The contrast is implicit: the disciples did what the ruler would not. Peter&#8217;s statement is not self-congratulation but an implicit question about reward &#8212; which Jesus&#8217;s answer (vv.29&#8211;30) addresses. The &#8220;we have left all&#8221; is the condition of discipleship that the cross makes possible: &#8220;whoever wants to be my disciple must deny themselves and take up their cross daily and follow me&#8221; (9:23).</p>",
    "29": "<p>&#8220;Truly I tell you, no one who has left home or wife or brothers or parents or children for the sake of the kingdom of God&#8221; &#8212; the list of what is left (home, wife, family) is the sacrifice of the fundamental goods of Jewish society &#8212; the very goods the Rich Ruler was unwilling to sacrifice. The &#8220;for the sake of the kingdom of God&#8221; is the Christological motivation: the disciples leave these goods not for asceticism but because Christ and his kingdom are worth more. The kingdom-exchange economy operates: what is left for the kingdom is returned multiplied in the kingdom community and in the age to come.</p>",
    "30": "<p>&#8220;Will fail to receive many times as much in this age, and in the age to come eternal life&#8221; &#8212; the double reward: present and eschatological. The &#8220;many times as much in this age&#8221; is the new community of brothers and sisters in Christ (Acts 2:44&#8211;45: the sharing community); the eternal life in the age to come is the resurrection inheritance. Christologically, the one who promises this reward is the one who himself left all &#8212; home (&#8220;the Son of Man has nowhere to lay his head&#8221;, 9:58), family (8:21), and ultimately life &#8212; and received in return the universal dominion of Phil 2:9&#8211;11. His pattern is the pattern of the promise.</p>",
    "31": "<p>&#8220;Jesus took the Twelve aside and told them: We are going up to Jerusalem, and everything that is written by the prophets about the Son of Man will be fulfilled&#8221; &#8212; the third passion prediction (cf. 9:22,44) is the most explicit about Scriptural fulfillment. The &#8220;everything written by the prophets&#8221; identifies the cross as the fulfillment of the whole prophetic stream &#8212; not one or two proof-texts but the entire prophetic witness. The risen Christ&#8217;s Emmaus teaching (24:27,44&#8211;46) will unpack what &#8220;everything written by the prophets&#8221; means: Moses, all the Prophets, and the Psalms all speak of the Messiah&#8217;s suffering and glory.</p>",
    "32": "<p>&#8220;He will be handed over to the Gentiles. They will mock him, insult him and spit on him&#8221; &#8212; the passion prediction&#8217;s detail is remarkable: handed over to Gentiles, mocked, insulted, spat upon. Each element will be literally fulfilled: handed to Pilate (23:1), mocked by Herod&#8217;s soldiers (23:11) and the Roman soldiers (23:36), insulted at the cross (23:35&#8211;39). The spitting recalls the Servant of Isa 50:6 (&#8220;I did not hide my face from mocking and spitting&#8221;). The deliberateness of the prediction &#8212; including the specific Gentile and national-shame elements &#8212; demonstrates that the passion is not defeat but the execution of the divine plan.</p>",
    "33": "<p>&#8220;They will flog him and kill him. On the third day he will rise again&#8221; &#8212; the flogging fulfills Isa 53:5 (&#8220;by his wounds we are healed&#8221;; the Hebrew <em>chaburah</em>/<em>makkah</em> means a lashing wound). The death and third-day resurrection is the central pattern of the new covenant&#8217;s inauguration (Hos 6:2: &#8220;after two days he will revive us; on the third day he will restore us&#8221;; Jonah&#8217;s three days: Matt 12:40). The precision of the prediction &#8212; the third day &#8212; transforms the passion from random tragedy into the divinely ordained act by which the new covenant is ratified and the resurrection secured.</p>",
    "34": "<p>&#8220;The disciples did not understand any of this. Its meaning was hidden from them, and they did not know what he was talking about&#8221; &#8212; the triple statement of incomprehension (did not understand, hidden, did not know) emphasizes the complete failure of the disciples to receive the passion prediction. The hiddenness is passive divine agency &#8212; God conceals for the time being. Luke&#8217;s emphasis is not on the disciples&#8217; stupidity but on the eschatological revelation required for understanding: the cross and resurrection must happen before the Scriptures&#8217; meaning becomes clear (24:45: &#8220;he opened their minds so they could understand the Scriptures&#8221;).</p>",
    "35": "<p>&#8220;As Jesus approached Jericho, a blind man was sitting by the roadside begging&#8221; &#8212; the blind man at Jericho is placed immediately after the disciples&#8217; blindness (v.34: they cannot see the meaning of the passion prediction). The structural irony is Luke&#8217;s commentary: the physically blind man will receive sight; the spiritually blinded disciples will not receive it until the resurrection. Jericho is the city of Joshua&#8217;s first conquest (Josh 6) &#8212; the entry into the Promised Land. Jesus approaching Jericho on his way to Jerusalem is the approach of the greater Joshua (Yēshua = Jesus) to his final conquest, the cross.</p>",
    "36": "<p>&#8220;When he heard the crowd going by, he asked what was happening&#8221; &#8212; the blind man&#8217;s initial dependence on hearing mirrors the situation of those who have not yet seen Christ but are informed about him through testimony. The crowd&#8217;s witness (v.37: &#8220;Jesus of Nazareth is passing by&#8221;) is the testimony that enables faith. The Christological principle: faith comes from hearing (Rom 10:17: &#8220;faith comes from hearing the message, and the message is heard through the word about Christ&#8221;). The blind man&#8217;s hearing creates the opportunity for the sight-giving encounter.</p>",
    "37": "<p>&#8220;They told him: Jesus of Nazareth is passing by&#8221; &#8212; the identification of Jesus as &#8220;of Nazareth&#8221; is the historical, human identification &#8212; the one from the obscure Galilean village. The blind man who receives this report responds with a Christological title that exceeds the crowd&#8217;s identification (v.38: &#8220;Son of David&#8221;) &#8212; demonstrating that his spiritual sight, even in physical blindness, surpasses the crowd&#8217;s. The contrast between the crowd&#8217;s &#8220;Jesus of Nazareth&#8221; and the blind man&#8217;s &#8220;Son of David&#8221; is the contrast between mere historical awareness and confessional faith.</p>",
    "38": "<p>&#8220;He called out: Jesus, Son of David, have mercy on me!&#8221; &#8212; &#8220;Son of David&#8221; is the messianic title that identifies Jesus as the heir of the Davidic covenant (2 Sam 7:12&#8211;16; Isa 11:1&#8211;10). The blind man&#8217;s use of the title is a confession of faith in Jesus as the Messiah &#8212; and the Messiah is the one who restores sight to the blind (Isa 35:5: &#8220;the eyes of the blind will be opened&#8221;; 42:7: &#8220;to open eyes that are blind&#8221;). His cry for mercy (<em>eleēson</em>) repeats the Kyrie Eleison of the ten lepers (17:13) &#8212; the prayer that reaches the heart of Christ.</p>",
    "39": "<p>&#8220;Those who led the way rebuked him and told him to be quiet, but he shouted all the more: Son of David, have mercy on me!&#8221; &#8212; the persistence of the blind man through opposition is the parable of the persistent widow (18:1&#8211;8) enacted in narrative. The crowd&#8217;s rebuke parallels the disciples&#8217; rebuke of those bringing infants (18:15) &#8212; in both cases Jesus overrides the disciples to welcome the apparently marginalized. The blind man&#8217;s louder cry under pressure demonstrates the faith that the parable of the widow called for: do not give up (v.1). Persistence before Christ is honored.</p>",
    "40": "<p>&#8220;Jesus stopped and ordered the man to be brought to him. When he came near, Jesus asked him&#8230;&#8221; &#8212; the stopping of Jesus at the cry of a single blind beggar in a crowd on the road to Jerusalem (where the cross awaits) reveals the consistent Christological priority: individual need commands the full attention of the one on the universal mission. The pattern repeats throughout Luke: Jairus&#8217;s daughter and the hemorrhaging woman interrupt one another; Zacchaeus stops the procession. The Son of Man who &#8220;came to seek and save the lost&#8221; (19:10) stops for each one individually.</p>",
    "41": "<p>&#8220;What do you want me to do for you? Lord, I want to see (<em>anableps&#333;</em>)&#8221; &#8212; Jesus&#8217;s question is the question of the patient, hearing Savior &#8212; &#8220;what do you want me to do for you?&#8221; is also asked of James and John (Mark 10:36), but there the answer is self-serving ambition; here it is the genuine need of the blind. The specific request (<em>hina anablepsō</em>) is fulfilled in v.43. The blind man&#8217;s answer is the model prayer: specific, concrete, addressed to the Lord&#8217;s capacity and compassion. He does not say &#8220;if you want&#8221; &#8212; he trusts that Christ both can and will.</p>",
    "42": "<p>&#8220;Jesus said to him: Receive your sight; your faith has healed you (<em>ses&#333;ken</em>)&#8221; &#8212; the salvation-word again (cf. 7:50; 8:48; 17:19). The healing-salvation formula is the consistent Christological signature: the physical restoration is simultaneously a sign of the eschatological salvation that Christ gives. &#8220;Son of David&#8221; faith produces &#8220;saved&#8221; healing &#8212; the blind man&#8217;s Davidic-messianic confession is the faith that receives the Servant&#8217;s gift of sight (Isa 35:5; 42:7). The command &#8220;receive your sight&#8221; (<em>anablepson</em>) is the word alone &#8212; no touch, no action, only the Son of David&#8217;s sovereign speech.</p>",
    "43": "<p>&#8220;Immediately he received his sight and followed Jesus, praising God&#8221; &#8212; the healing produces discipleship and doxology. &#8220;Followed Jesus&#8221; (<em>ēkolouthei aut&#333;</em>) on the road to Jerusalem is following the one who goes to the cross &#8212; the newly sighted man joins the passion-procession. His praise of God echoes throughout Luke&#8217;s healings (5:25&#8211;26; 7:16; 13:13; 17:15&#8211;16) and anticipates the crowd&#8217;s praise at the Triumphal Entry (19:37&#8211;38). The people&#8217;s echo of his praise is the spreading of the doxology &#8212; the community drawn into worship by the sight-giving of the Son of David who is himself the light of the world (John 9:5).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, DATA)
    merge_comm(existing, FILL_CH17)
    merge_comm(existing, FILL_CH18)
    save_comm('mkt-christ', 'luke', existing)
    total = sum(len(v) for v in existing.values())
    print(f"Luke mkt-christ: {len(existing)} chapters, {total} verses written.")

if __name__ == '__main__':
    main()
